import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';

function MyVideosPage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deletingId, setDeletingId] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem('access');
    if (!token) {
      navigate('/login');
      return;
    }
    
    fetchVideos();
  }, [navigate]);

  const fetchVideos = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://localhost:8000/api/videos/', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      // Фильтруем только видео текущего пользователя
      const currentUser = getCurrentUser();
      const userVideos = response.data.filter(v => v.uploaded_by_name === currentUser);
      setVideos(userVideos);
      setLoading(false);
    } catch (error) {
      console.error('Ошибка загрузки:', error);
      setLoading(false);
    }
  };

  const getCurrentUser = () => {
    const token = localStorage.getItem('access');
    if (!token) return null;
    try {
      const payload = JSON.parse(atob(token.split('.')[1]));
      return payload.username;
    } catch (e) {
      return null;
    }
  };

  const handleDelete = async (videoId) => {
    if (!window.confirm('Вы уверены, что хотите удалить это видео?')) {
      return;
    }
    
    setDeletingId(videoId);
    try {
      const token = localStorage.getItem('access');
      await axios.delete(`http://localhost:8000/api/videos/${videoId}/`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      // Обновляем список после удаления
      setVideos(videos.filter(v => v.id !== videoId));
      alert('Видео удалено');
    } catch (error) {
      console.error('Ошибка удаления:', error);
      alert('Не удалось удалить видео');
    } finally {
      setDeletingId(null);
    }
  };

  if (loading) {
    return <div style={{ color: 'white', textAlign: 'center', marginTop: 50 }}>Загрузка...</div>;
  }

  return (
    <div style={{ maxWidth: 1200, margin: '0 auto', padding: 20 }}>
      <h1 style={{ color: 'white', marginBottom: 30 }}>Мои видео</h1>
      
      {videos.length === 0 ? (
        <div style={{ textAlign: 'center', color: '#aaa', marginTop: 50 }}>
          <p>У вас пока нет загруженных видео</p>
          <Link to="/upload" style={{ color: '#ff0000' }}>Загрузить первое видео</Link>
        </div>
      ) : (
        <div style={{ display: 'grid', gap: 20 }}>
          {videos.map(video => (
            <div key={video.id} style={{
              backgroundColor: '#1a1a1a',
              borderRadius: 12,
              padding: 15,
              display: 'flex',
              gap: 20,
              alignItems: 'center'
            }}>
              {/* Превью */}
              <div style={{ width: 200, flexShrink: 0 }}>
                {video.thumbnail ? (
                  <img 
                    src={`http://localhost:8000${video.thumbnail}`}
                    alt={video.title}
                    style={{ width: '100%', borderRadius: 8 }}
                  />
                ) : (
                  <div style={{
                    width: '100%',
                    aspectRatio: '16/9',
                    backgroundColor: '#272727',
                    borderRadius: 8,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: 30
                  }}>
                    🎬
                  </div>
                )}
              </div>
              
              {/* Информация */}
              <div style={{ flex: 1 }}>
                <Link to={`/video/${video.id}`} style={{ textDecoration: 'none' }}>
                  <h3 style={{ color: 'white', marginBottom: 8 }}>{video.title}</h3>
                </Link>
                <p style={{ color: '#aaa', fontSize: 14, marginBottom: 5 }}>
                  {video.description || 'Нет описания'}
                </p>
                <p style={{ color: '#888', fontSize: 12 }}>
                  👁️ {video.views || 0} просмотров • 📅 {new Date(video.created_at).toLocaleDateString()}
                </p>
              </div>
              
              {/* Кнопка удаления */}
              <button
                onClick={() => handleDelete(video.id)}
                disabled={deletingId === video.id}
                style={{
                  backgroundColor: '#ff0000',
                  color: 'white',
                  border: 'none',
                  padding: '8px 16px',
                  borderRadius: 8,
                  cursor: deletingId === video.id ? 'not-allowed' : 'pointer',
                  fontSize: 14
                }}
              >
                {deletingId === video.id ? 'Удаление...' : '🗑️ Удалить'}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default MyVideosPage;
